// === $N_Sub_Norm: subtraction noun operators (forward: A - B) ===
const N_SUB_NORM = new Set(['subtraction']);
// === $N_Mul: multiplication noun operators ===
const N_MUL = new Set(['multiplication']);
// === $N_Div: division noun operators ===
const N_DIV = new Set(['division']);
// === Noise words (stripped from math but counted for syllables) ===
const NOISE_SINGLE = new Set(['type','shit','influence']);


// ============================================================================
// COUNTKU CONVERTER — Plaintext math engine
// ============================================================================

class CountkuConverter {
  constructor() {
    this.variantUsage = {};
    this.andStyle = null;  // 'with-and' | 'no-and' | null
    this.resetVariants();
  }

  resetVariants() {
    this.variantUsage = { 'zero_variant':null, 'and_variant':null,
                          'times_variant':null, 'e_variant':null };
    this.andStyle = null;
  }

  // --- Get syllable count for a word ---
  getSyllables(word) {
    const w = word.toLowerCase();
    if (COUNTKU_DB[w]) return COUNTKU_DB[w].syl || 0;
    if (COUNTKU_ORDINALS[w]) return COUNTKU_ORDINALS[w].syl;
    // Check multi-word
    for (const m of COUNTKU_MULTI) {
      if (m.words.length === 1 && m.words[0] === w) return m.syl;
    }
    return null;
  }

  // --- Check variant consistency ---
  checkVariant(word) {
    const w = word.toLowerCase();
    for (const [group, words] of Object.entries(VARIANT_GROUPS)) {
      if (words.includes(w)) {
        if (this.variantUsage[group] === null) this.variantUsage[group] = w;
        else if (this.variantUsage[group] !== w) {
          return `Variant conflict: You used "${this.variantUsage[group]}" before, cannot use "${w}" now!`;
        }
      }
    }
    return null;
  }

  // --- Tokenize input, handling multi-word patterns ---
  tokenize(text) {
    // Strip trailing punctuation and commas
    const clean = text.replace(/[.!?]+$/, '').replace(/,/g, '').trim();
    if (!clean) return [];

    const rawWords = clean.split(/\s+/);
    const tokens = [];
    let i = 0;

    while (i < rawWords.length) {
      // Try multi-word patterns (longest first)
      let matched = false;
      // Sort by length descending
      const sortedMulti = [...COUNTKU_MULTI].sort((a,b) => b.words.length - a.words.length);

      for (const pattern of sortedMulti) {
        const len = pattern.words.length;
        if (i + len > rawWords.length) continue;
        const slice = rawWords.slice(i, i + len).map(w => w.toLowerCase());
        if (slice.join(' ') === pattern.words.join(' ')) {
          tokens.push({ type: 'multi', pattern: pattern, words: slice });
          i += len;
          matched = true;
          break;
        }
      }
      if (matched) continue;

      // Single word
      const w = rawWords[i].toLowerCase();
      tokens.push({ type: 'single', word: w, raw: rawWords[i] });
      i++;
    }

    return tokens;
  }

  // --- Convert tokens to math expression (FIXED v2) ---
  convertTokens(tokens) {
    const parts = [];
    let openParens = 0;
    let lastWasNumber = false;
    let lastNumberValue = 0;
    let pendingHalf = false;
    let pendingDouble = false;
    let pendingTwice = false;
    let inDecimal = false;
    let expectingFuncClose = false;
    let prepMode = null;
    let ordinalMode = null;
    let ordinalRootDegree = null;
    let pendingLogBase = null;  // null | '10' | 'natural' | number - for change-of-base logs
    let decimalContext = false; // true after decimal point, for digit concatenation
    let lastW = { num: null, var: null, func: null, fluff: null, prep: null };
    // v6: Deferred emission for power/root with large composed ordinals
    let deferredMode = null;     // null | 'power' | 'root'
    let deferredBaseExpr = null; // expression before trigger
    let deferredDegree = null;   // degree string (from ordinal)
    let deferredPrefix = null;   // for $P_Passiv: parts before last term
    let degreeSum = 0;           // running sum for degree (multiplier + ordinal)
    let degreeLast = 0;          // last number for composition
    let inDegreePhase = true;    // true = collecting degree, false = collecting argument
    // Noun operator preposition gating: stores pending operator until preposition validates it
    let nounOpPending = null;    // null | '/' | '*' | '+' | '-'
    // Log pend mode: to/with/by/using {a/the} logarithm → applies to previous number
    let logPendMode = null;      // null | 'prev' | 'natural_prev'
    let funcArgOpen = false;     // true when ANY function arg is being collected
    let logBaseOpen = false;     // true when log base denominator is being collected
    let lastLogWasNatural = false;  // tracks if last closed log was natural

    const updateLastW = (type, value) => {
      if (type === 'num') lastW.num = value;
      else if (type === 'var') lastW.var = value;
      else if (type === 'func') lastW.func = value;
      else if (type === 'fluff') lastW.fluff = value;
      else if (type === 'prep') lastW.prep = value;
    };

    // v6: Extract trailing numeric degree from parts (e.g., ['5','-','*1000000','40','7'] → {degree:'1000047', prefix:['5','-']})
    const extractDegree = (partsArr) => {
      const degreeParts = [];
      let j = partsArr.length - 1;
      while (j >= 0 && (/^\d+$/.test(partsArr[j]) || partsArr[j].startsWith('*'))) {
        degreeParts.unshift(partsArr[j]);
        j--;
      }
      if (degreeParts.length === 0) return { degree: lastW.num || '1', prefix: partsArr };
      // Evaluate degree parts (e.g., ['*1000000','40','7'] → 1000000+40+7 = 1000047)
      let degree = 0;
      for (const p of degreeParts) {
        if (p.startsWith('*')) degree += parseInt(p.substring(1), 10);
        else degree += parseInt(p, 10);
      }
      return { degree: String(degree), prefix: partsArr.slice(0, j + 1) };
    };

    // v7.3: Check if next token would compose with current number (for function args)
    const nextWouldCompose = (idx) => {
      const nextTok = tokens[idx + 1];
      return nextTok && nextTok.type === 'single' &&
        COUNTKU_DB[nextTok.word] &&
        (COUNTKU_DB[nextTok.word].type === 'number' ||
         COUNTKU_DB[nextTok.word].type === 'multiplier' ||
         COUNTKU_DB[nextTok.word].type === 'ordinal' ||
         nextTok.word === 'and' || nextTok.word === 'point');
    };

    const maybeCloseFunc = (currentIdx) => {
      // v7.3: Close log base paren after composition finishes
      if (logBaseOpen && currentIdx !== undefined && !nextWouldCompose(currentIdx)) {
        parts.push(')');
        logBaseOpen = false;
        return;
      }
      if (expectingFuncClose && openParens > 0) {
        // Don't close if next token would compose (e.g., "thirty eight" inside log)
        if (currentIdx !== undefined && funcArgOpen && nextWouldCompose(currentIdx)) {
          return;  // Wait for full composition
        }
        if (ordinalMode && ordinalRootDegree) {
          if (ordinalMode === 'root') parts.push(',1/' + ordinalRootDegree + ')');
          else if (ordinalMode === 'power') parts.push(',' + ordinalRootDegree + ')');
          ordinalMode = null; ordinalRootDegree = null;
        } else {
          parts.push(')');
          // d18/d20: Change-of-base log: log(A)/log(base)
          if (pendingLogBase && pendingLogBase !== 'natural') {
            parts.push('/Math.log(' + pendingLogBase + ')');
          }
          // v7.4: secant/cosecant/cotangent close second paren (the 1/ fraction)
          if (openParens > 1) {
            parts.push(')');
            openParens--;
          }
        }
        openParens--; expectingFuncClose = false;
        lastLogWasNatural = (pendingLogBase === 'natural');
        pendingLogBase = null;
        funcArgOpen = false;
      }
    };

    for (let i = 0; i < tokens.length; i++) {
      const tok = tokens[i];
      let math = null;

      // === Handle multi-word patterns ===
      if (tok.type === 'multi') {
        const pat = tok.pattern;

        // Noise: skip
        if (pat.noise) continue;

        // d41: [The] subtraction from → FLIP (B - A instead of A - B)
        if (pat.math === 'FLIP_SUB') {
          parts.push('__FLIP__');
          continue;
        }

        // d37: Half of → (1/2)*
        if (pat.op === 'd37') {
          pendingHalf = true;
          continue;
        }

        // d38: Double → 2*
        if (pat.op === 'd38') {
          pendingDouble = true;
          continue;
        }

        // Trig functions (sine of, cosine of) — open paren, expect arg
        if (pat.math === 'Math.sin(' || pat.math === 'Math.cos(' || pat.math === 'Math.tan(') {
          math = pat.math;
          openParens++;
          expectingFuncClose = true;
          funcArgOpen = true;
        }
        // Secant/cosecant/cotangent/inverse: open TWO parens (fraction + func)
        else if (pat.math === '(1/Math.cos(' || pat.math === '(1/Math.sin(' ||
            pat.math === '(1/Math.tan(' || pat.math === '(1/') {
          math = pat.math;
          openParens += 2;  // (1/ + Math.cos(
          expectingFuncClose = true;
          funcArgOpen = true;
        }
        // Other functions that open parens
        else if (pat.math === 'Math.sqrt(' || pat.math === 'Math.cbrt(' ||
            pat.math === 'Math.log(' || pat.math === 'Math.abs(') {
          // v7.3: to/with/by/using logarithm → apply to previous expression
          if (logPendMode && (pat.math === 'Math.log(')) {
            const prevExpr = parts.join('') || '0';
            parts.length = 0;
            math = 'Math.log(';
            openParens++;
            expectingFuncClose = true;
            parts.push(math);
            parts.push(prevExpr);  // Inject previous expression as argument
            if (logPendMode === 'natural_prev') {
              pendingLogBase = 'natural';
            } else {
              pendingLogBase = '10';
            }
            logPendMode = null;
            math = null;  // Already pushed
          } else {
            math = pat.math;
            openParens++;
            expectingFuncClose = true;
            funcArgOpen = true;
            // d16: Natural log patterns — no change-of-base
            const isNaturalLog = pat.words && (pat.words.includes('natural') || pat.op === 'd16');
            if (isNaturalLog) {
              pendingLogBase = 'natural';
            } else if (pat.math === 'Math.log(') {
              pendingLogBase = '10';  // Default: change of base to 10
            }
          }
        }
        // Ordinal roots
        else if (pat.ordinal && pat.root) {
          math = pat.math; ordinalRootDegree = pat.ordinal; ordinalMode = 'root';
          openParens++; expectingFuncClose = true; updateLastW('func', 'root');
        }
        // Ordinal powers
        else if (pat.ordinal && pat.power) {
          math = pat.math; ordinalRootDegree = pat.ordinal; ordinalMode = 'power';
          openParens++; expectingFuncClose = true; updateLastW('func', 'power');
        }
        // Power
        else if (pat.math === '**') {
          math = pat.math;
        }
        // Operators
        else {
          math = pat.math;
        }
      }
      // === Handle single-word tokens ===
      else if (tok.type === 'single') {
        const w = tok.word;
        const db = COUNTKU_DB[w];

        // v6: Deferred root — "million and forty seventh root of five"
        if (w === 'root' && lastW.num !== null && !deferredMode) {
          const extracted = extractDegree(parts);
          deferredMode = 'root';
          deferredBaseExpr = null;
          deferredDegree = extracted.degree;
          deferredPrefix = extracted.prefix;
          degreeSum = parseInt(extracted.degree, 10) || 0;
          degreeLast = 0; inDegreePhase = true;
          parts.length = 0;  // Clear parts to collect argument
          inDecimal = false;
          continue;
        }
        // v6: "power" in deferred power mode → noise (already have degree)
        else if (w === 'power' && deferredMode === 'power') {
          continue;  // Noise when already in deferred power mode
        }
        // === -ed forms: "with a subtracted three" → 10-3 ===
        // These work after with/using {a} WITHOUT a trailing preposition
        if (prepMode === 'action' && (w === 'subtracted' || w === 'multiplied' || w === 'divided' || w === 'added')) {
          const edOps = { 'subtracted': '-', 'multiplied': '*', 'divided': '/', 'added': '+' };
          parts.push(edOps[w]);
          prepMode = null;  // Consume the action prepMode
          lastWasNumber = false;
          continue;
        }

        // === Log pend trigger: to/with/by/using {a/the} [natural] logarithm → applies to previous number ===
        if ((w === 'to' || w === 'with' || w === 'by' || w === 'using') && !logPendMode && !deferredMode) {
          const n1 = tokens[i + 1];
          const n2 = tokens[i + 2];
          const n3 = tokens[i + 3];
          // Helper: get word from single or multi token
          const getW = (t, idx) => { if (!t) return null; if (t.type === 'multi') return t.words[idx || 0]; return t.word; };
          // Match: {to/with/by/using} [a/the] [natural] logarithm/log
          // Check ALL words in multi-word tokens
          const wordsIn = (t) => { if (!t) return []; if (t.type==='multi') return t.words; return [t.word]; };
          const allWords = [...wordsIn(n1), ...wordsIn(n2), ...wordsIn(n3)];
          const hasNatural = allWords.includes('natural');
          const hasLog = allWords.includes('log') || allWords.includes('logarithm');
          if (hasLog) {
            logPendMode = hasNatural ? 'natural_prev' : 'prev';
            prepMode = null;  // Consume prepMode
            lastWasNumber = false;
            continue;
          }
        }

        // v7.3: "base" after non-natural log → change log base to following number
        if (w === 'base' && !expectingFuncClose) {
          if (lastLogWasNatural) {
            // After natural log: consume "base" + next number as noise
            const nextTok = tokens[i + 1];
            if (nextTok && nextTok.type === 'single' && COUNTKU_DB[nextTok.word] && COUNTKU_DB[nextTok.word].type === 'number') {
              // Skip both "base" and the following number
              i++;  // Skip next token (number)
            }
            continue;  // "base" is noise after natural log
          }
          // Check if last expression was a base-10 log
          const lastPart = parts[parts.length - 1];
          if (lastPart && lastPart === '/Math.log(10)') {
            parts.pop();  // Remove base-10 denominator
            pendingLogBase = 'pending';  // Will be set by next number
          }
          continue;
        }

        // === Noun operator preposition gating ===
        // division/multiplication/addition/subtraction are ONLY valid with approved prepositions
        if (nounOpPending) {
          const approvedMul = w === 'by' || w === 'with' || w === 'using' || w === 'of';
          const approvedDiv = w === 'by' || w === 'with' || w === 'using';
          const approvedAdd = w === 'with' || w === 'by' || w === 'using';
          const approvedSub = w === 'by' || w === 'with' || w === 'using' || w === 'of';
          let fire = false;
          if (nounOpPending === '/' && approvedDiv) fire = true;
          else if (nounOpPending === '*' && approvedMul) fire = true;
          else if (nounOpPending === '+' && approvedAdd) fire = true;
          else if (nounOpPending === '-' && approvedSub) fire = true;
          // "from" with division: denominator rule → prev / next
          if (nounOpPending === '/' && w === 'from') {
            parts.push('/'); nounOpPending = null; continue;
          }
          // "from" with subtraction: d41 FLIP_SUB
          if (nounOpPending === '-' && w === 'from') {
            parts.push('__FLIP__'); nounOpPending = null; continue;
          }
          // "to" with multiplication/addition: NO math (prevent ** glitch)
          if ((nounOpPending === '*' || nounOpPending === '+') && w === 'to') {
            nounOpPending = null; continue;  // Noise
          }
          if (fire) {
            parts.push(nounOpPending); nounOpPending = null; continue;
          }
          // Unapproved preposition: noun operator is noise
          nounOpPending = null;
          // Fall through to normal processing of this word
        }
        // FIX v2: Check ordinal+root/power BEFORE db type checks
        else if (w === 'root' && lastW.num !== null) {
          const degree = lastW.num;
          if (parts.length > 0 && parts[parts.length - 1] === degree) parts.pop();
          math = 'Math.pow('; ordinalRootDegree = degree; ordinalMode = 'root';
          openParens++; expectingFuncClose = true; updateLastW('func', 'root'); inDecimal = false;
        }
        else if (w === 'power' && lastW.num !== null) {
          const degree = lastW.num;
          if (parts.length > 0 && parts[parts.length - 1] === degree) parts.pop();
          math = 'Math.pow('; ordinalRootDegree = degree; ordinalMode = 'power';
          openParens++; expectingFuncClose = true; updateLastW('func', 'power'); inDecimal = false;
        }
        else if (!db) {
          // Check ordinals (first, second, third, etc.)
          if (COUNTKU_ORDINALS[w]) {
            math = COUNTKU_ORDINALS[w].val;
            // v6: degree accumulation during deferred mode
            if (deferredMode && inDegreePhase) {
              const n = parseInt(math, 10);
              if (lastWasNumber && degreeLast > 0) { degreeLast += n; }
              else { degreeLast = n; }
            }
            // FIX 2: Compose ordinal with preceding number (forty seventh → 47)
            if (lastWasNumber && parts.length > 0) {
              const lastPart = parts[parts.length - 1];
              if (/^\d+$/.test(lastPart)) {
                const composed = parseInt(lastPart, 10) + parseInt(math, 10);
                math = String(composed);
                parts[parts.length - 1] = math;  // Replace last part with composed value
                lastNumberValue = composed;
                updateLastW('num', math);
                lastWasNumber = true;
                continue;  // Skip the push below, already updated parts
              }
            }
            updateLastW('num', math);
            lastWasNumber = true;
          } else {
            return { error: `Unknown word: "${w}"` };
          }
        }
        // Noise
        else if (db.type === 'noise') {
          continue;
        }
        // Helper — prepositional flags, after, delimiters
        else if (db.type === 'helper') {
          // 'after' closes function parens
          if (db.closeFunc && openParens > 0) {
            while (openParens > 0) { parts.push(')'); openParens--; }
            expectingFuncClose = false;
          }
          // v6: "to" with preceding number → deferred power mode
          // Skip if next tokens indicate log pattern ("to the logarithm")
          const nextForLog = tokens[i + 1];
          const next2ForLog = tokens[i + 2];
          const isLogPat = nextForLog && (
            (nextForLog.word === 'the' && next2ForLog && (next2ForLog.word === 'log' || next2ForLog.word === 'logarithm')) ||
            (nextForLog.word === 'log' || nextForLog.word === 'logarithm')
          );
          if (w === 'to' && lastW.num !== null && !deferredMode && !isLogPat) {
            deferredMode = 'power';
            deferredBaseExpr = parts.join('');  // Everything before "to" is the base
            deferredDegree = lastW.num;
            deferredPrefix = null;
            degreeSum = 0; degreeLast = 0; inDegreePhase = true;
            parts.length = 0;  // Clear parts to collect exponent
            continue;
          }
          // $P_Action: "using", "with", "by" — sets active connective mode
          if (db.pAction) { prepMode = 'action'; lastWasNumber = false; continue; }
          // $P_Passiv: "undergoing", "under" — sets passive connective mode
          if (db.pPassiv) { prepMode = 'passiv'; lastWasNumber = false; continue; }
          // v6: "of" in deferred root mode → switch from degree to argument
          if (w === 'of' && deferredMode === 'root' && inDegreePhase) {
            degreeSum += degreeLast;
            inDegreePhase = false;
            continue;
          }
          // v6: During deferred mode, "and" is degree addition separator
          if (w === 'and' && deferredMode && inDegreePhase) {
            degreeSum += degreeLast;
            degreeLast = 0;
            continue;
          }
          // Noun operators are GATED on approved prepositions (see below)
          // Store the operator and wait for next token to validate
          if (db.nDiv) { nounOpPending = '/'; prepMode = null; continue; }
          else if (db.nMul) { nounOpPending = '*'; prepMode = null; continue; }
          else if (db.nAdd) { nounOpPending = '+'; prepMode = null; continue; }
          else if (db.nSub) { nounOpPending = '-'; prepMode = null; continue; }
          else { continue; }
        }
        // Decimal zero (oh)
        else if (db.type === 'special' && db.role === 'decimal_zero') {
          if (inDecimal) {
            math = '0';
          } else {
            return { error: `"oh" can only be used after a decimal point (e.g., \"one point oh\")` };
          }
        }
        // Number
        else if (db.type === 'number') {
          math = db.val;
          inDecimal = false;
          updateLastW('num', math);
          // v7.3: pending base after "log ... base" → use this number as base
          // Open paren for base, let maybeCloseFunc close after composition
          if (pendingLogBase === 'pending') {
            parts.push('/Math.log(');
            parts.push(math);
            logBaseOpen = true;
            lastLogWasNatural = false;
            pendingLogBase = null;
            lastWasNumber = true;
            math = null;  // Already pushed, fall through to close handling
          }
          // v6: degree accumulation during deferred mode
          if (deferredMode && inDegreePhase) {
            const n = parseInt(math, 10);
            if (lastWasNumber && degreeLast > 0) { degreeLast += n; }
            else { degreeLast = n; }
          }
        }
        // Ordinal (systematic/latin forms: quadratic, cubic, quartic, etc.)
        else if (db.type === 'ordinal') {
          math = db.val;
          updateLastW('num', math);
          updateLastW('var', math);
          lastWasNumber = true;
          // v6: degree accumulation during deferred mode
          if (deferredMode && inDegreePhase) {
            const n = parseInt(math, 10);
            if (degreeLast > 0) { degreeLast += n; }
            else { degreeLast = n; }
          }
        }
        // Decimal point
        else if (db.type === 'decimal') {
          math = db.val;
          inDecimal = true;
          decimalContext = true;
        }
        // Multiplier (hundred, thousand, million, billion)
        else if (db.type === 'multiplier') {
          math = db.val;
          // Track accumulated scale value for degree calculation
          if (lastWasNumber && lastW.num !== null) {
            const baseVal = parseInt(lastW.num, 10);
            const multVal = db.base || parseInt(math.substring(1), 10);
            const product = baseVal * multVal;
            updateLastW('num', String(product));
          }
          // v6: degree accumulation during deferred mode
          if (deferredMode && inDegreePhase) {
            const multVal = db.base || parseInt(math.substring(1), 10);
            if (degreeLast > 0) {
              degreeSum += degreeLast * multVal; degreeLast = 0;
            } else {
              degreeSum = multVal;
            }
          }
        }
        // Operator
        else if (db.type === 'operator') {
          // Postfix operators (squared, cubed) must close function parens first
          if ((w === 'squared' || w === 'cubed') && openParens > 0) {
            while (openParens > 0) { parts.push(')'); openParens--; }
          }
          math = db.val;
          inDecimal = false;
        }
        // Constant
        else if (db.type === 'constant') {
          math = db.val;
        }
        // Function trigger (single-word: log, root, sine, cosine, tan)
        else if (db.type === 'function') {
          // v7.3: to/with/by/using logarithm → apply to previous expression
          if (logPendMode && (w === 'log' || w === 'logarithm')) {
            const prevExpr = parts.join('') || '0';
            parts.length = 0;
            math = 'Math.log(';
            openParens++;
            expectingFuncClose = true;
            funcArgOpen = true;
            parts.push(math);
            parts.push(prevExpr);
            if (logPendMode === 'natural_prev') {
              pendingLogBase = 'natural';
            } else {
              pendingLogBase = '10';
            }
            logPendMode = null;
            math = null;  // Already pushed
          } else {
            math = db.val;
            // v7.4: secant/cosecant/cotangent/inverse open TWO parens
            if (math.startsWith('(1/')) {
              openParens += 2;
            } else {
              openParens++;
            }
            expectingFuncClose = true;
            funcArgOpen = true;
            // d18/d20: Default log is change-of-base to 10; natural log skips this
            if (w === 'log' || w === 'logarithm') {
              // Check if preceded by an ordinal (e.g., "fourteenth log of six")
              if (lastW.num !== null) {
                pendingLogBase = lastW.num;  // Use ordinal as base
                // Remove ordinal from parts (base goes in denominator, not as multiplier)
                if (parts.length > 0 && parts[parts.length - 1] === lastW.num) {
                  parts.pop();
                }
              } else {
                pendingLogBase = '10';  // Default: log base 10
              }
            }
          }
        }
      }

      if (math === null) continue;

      // === Handle number composition ===
      // Track if this token is a number for func-close logic
      let isNumberToken = false;
      if (tok.type === 'single' && COUNTKU_DB[tok.word] &&
          (COUNTKU_DB[tok.word].type === 'number' ||
           (COUNTKU_DB[tok.word].type === 'special' && COUNTKU_DB[tok.word].role === 'decimal_zero') ||
           COUNTKU_DB[tok.word].type === 'ordinal')) {
        const isSimpleNum = SIMPLE_NUMBERS.has(tok.word);
        isNumberToken = true;

        if (isSimpleNum && lastWasNumber && parts.length > 0) {
          const lastPart = parts[parts.length - 1];
          // If last part is a pure number, compose
          if (/^\d+$/.test(lastPart)) {
            const lastVal = parseInt(lastPart, 10);
            const curVal = parseInt(math, 10);
            // Handle decimal composition
            if (decimalContext) {
              parts[parts.length - 1] = lastPart + math;  // e.g., "0" + "5" = "05"
              // v7.5: only consume decimalContext if next token is NOT a decimal digit
              const nextTok = tokens[i + 1];
              if (!nextTok || nextTok.type !== 'single' || !COUNTKU_DB[nextTok.word] ||
                  (COUNTKU_DB[nextTok.word].type !== 'number' &&
                   !(COUNTKU_DB[nextTok.word].type === 'special' && COUNTKU_DB[nextTok.word].role === 'decimal_zero'))) {
                decimalContext = false;  // End of decimal phase
              }
            } else {
              parts[parts.length - 1] = String(lastVal + curVal);
            }
            lastNumberValue = lastVal + curVal;
            // v7.4: close func if next token wouldn't compose
            maybeCloseFunc(i);
            continue;
          }
        }
        lastWasNumber = true;
        lastNumberValue = parseInt(math, 10) || 0;
      } else if (math && !math.startsWith('__')) {
        lastWasNumber = false;
      }

      // === Handle pending operations ===
      if (pendingHalf && math) {
        parts.push('(1/2)*' + math);
        pendingHalf = false;
        continue;
      }
      if (pendingDouble && math) {
        parts.push('2*' + math);
        pendingDouble = false;
        continue;
      }

      parts.push(math);
      // For number tokens, close function parens AFTER pushing the value
      if (isNumberToken) maybeCloseFunc(i);
    }

    // === FIX 1: Scale composition ===
    // Insert + between multiplier and following number: ['1','*100','23'] → ['1','*100','+','23']
    for (let i = 0; i < parts.length - 1; i++) {
      if (parts[i].startsWith('*') && /^\d+$/.test(parts[i + 1])) {
        parts.splice(i + 1, 0, '+');
        i++;
      }
    }

    // FIX: Close open parens with ordinal mode support
    while (openParens > 0) {
      if (ordinalMode && ordinalRootDegree) {
        if (ordinalMode === 'root') parts.push(',1/' + ordinalRootDegree + ')');
        else if (ordinalMode === 'power') parts.push(',' + ordinalRootDegree + ')');
        ordinalMode = null; ordinalRootDegree = null;
      } else {
        parts.push(')');
        // v7.3: Add log base denominator if pending
        if (pendingLogBase && pendingLogBase !== 'natural') {
          parts.push('/Math.log(' + pendingLogBase + ')');
        }
      }
      lastLogWasNatural = (pendingLogBase === 'natural');
      pendingLogBase = null;
      funcArgOpen = false;
      openParens--;
    }
    // v7.3: Close any open log base paren
    if (logBaseOpen) {
      parts.push(')');
      logBaseOpen = false;
    }

    // Handle __FLIP__ markers (d41: subtraction from)
    // Replace A __FLIP__ B with (B - A)
    let flipIdx = parts.indexOf('__FLIP__');
    while (flipIdx >= 0) {
      const before = parts.slice(0, flipIdx).join('');
      const after = parts.slice(flipIdx + 1).join('');
      parts.length = 0;
      parts.push('(' + after + ')-(' + before + ')');
      flipIdx = parts.indexOf('__FLIP__');
    }

    // v6: Deferred emission — construct final expression
    if (deferredMode === 'power') {
      const exponent = degreeSum + degreeLast;
      parts.length = 0;
      parts.push('(' + deferredBaseExpr + ')**' + exponent);
    } else if (deferredMode === 'root') {
      const degree = degreeSum + degreeLast;
      const arg = parts.join('') || '0';
      const prefix = deferredPrefix ? deferredPrefix.join('') : '';
      parts.length = 0;
      parts.push(prefix + 'Math.pow(' + arg + ',1/' + degree + ')');
    }

    return { expr: parts.join(''), parts: parts };
  }

  // === Main entry: convert word phrase to math expression ===
  convertPhrase(phrase) {
    const tokens = this.tokenize(phrase);
    if (!tokens.length) return null;
    const result = this.convertTokens(tokens);
    if (result.error) return result;
    return result.expr || null;
  }

  // === Count syllables in a phrase ===
  countSyllables(phrase) {
    const tokens = this.tokenize(phrase);
    let total = 0;
    for (const tok of tokens) {
      if (tok.type === 'multi') total += tok.pattern.syl;
      else if (tok.type === 'single') {
        const db = COUNTKU_DB[tok.word];
        if (db) total += db.syl || 0;
        else if (COUNTKU_ORDINALS[tok.word]) total += COUNTKU_ORDINALS[tok.word].syl;
      }
    }
    return total;
  }
}

const countkuConverter = new CountkuConverter();


// ============================================================================
// HAIKU VALIDATOR — Automatic 5-7-5 detection (no delimiters)
// ============================================================================

class HaikuValidator {
  constructor() {}

  /**
   * Parse input into automatic 5-7-5 lines
   * Returns: { isHaiku: bool, error: string|null, lines: [{words, syllables}] }
   */
  validate(phrase) {
    // Strip trailing punctuation and commas
    const clean = phrase.replace(/[.!?]+$/, '').replace(/,/g, '').trim();
    if (!clean) return { isHaiku: false, error: 'Empty input', lines: [] };

    const words = clean.split(/\s+/).filter(w => w);
    const lines = [];
    let currentLine = { words: [], syllables: 0 };
    const targets = [5, 7, 5];
    let lineIdx = 0;

    // Reset variant tracker for fresh validation
    countkuConverter.resetVariants();

    for (let i = 0; i < words.length; i++) {
      const word = words[i].toLowerCase();
      const wordSyl = countkuConverter.getSyllables(word);

      if (wordSyl === null) {
        return { isHaiku: false, error: `Unknown word: "${words[i]}"`, lines: [] };
      }

      // Check "subtracted from" error
      if (word === 'subtracted' && words[i + 1] && words[i + 1].toLowerCase() === 'from') {
        return {
          isHaiku: false,
          error: 'We do not currently support passive character integration. I.e. for "Six subtracted from five" the proper method is "five minus six", please try again.',
          lines: []
        };
      }

      // Check variant consistency
      const vErr = countkuConverter.checkVariant(word);
      if (vErr) return { isHaiku: false, error: vErr, lines: [] };

      const target = targets[lineIdx];
      const wouldExceed = currentLine.syllables + wordSyl > target;

      // If adding this word would exceed the line target
      if (wouldExceed) {
        // Can't start new line if we're already on line 3
        if (lineIdx >= 2) {
          return { isHaiku: false, error: `Too many syllables (exceeds 5-7-5)`, lines };
        }

        // Check anti-splicing: last word of current line must not be unspliceable
        if (currentLine.words.length > 0) {
          const lastWord = currentLine.words[currentLine.words.length - 1].toLowerCase();
          if (UNSPLICEABLE.has(lastWord)) {
            return { isHaiku: false, error: `Cannot split "${lastWord}" across lines`, lines: [] };
          }
        }

        // Save current line and start new one
        lines.push({ ...currentLine });
        lineIdx++;
        currentLine = { words: [], syllables: 0 };
      }

      // Add word to current line
      currentLine.words.push(words[i]);
      currentLine.syllables += wordSyl;

      // Check if line is exactly at target
      if (currentLine.syllables === targets[lineIdx]) {
        lines.push({ ...currentLine });
        if (lineIdx < 2) {
          lineIdx++;
          currentLine = { words: [], syllables: 0 };
        }
      }
    }

    // Don't forget the last line if it has words and we haven't saved it
    if (currentLine.words.length > 0 && lines.length < 3) {
      lines.push({ ...currentLine });
    }

    // Validate exactly 3 lines with 5-7-5
    if (lines.length !== 3) {
      return { isHaiku: false, error: `Expected 3 lines (5-7-5), got ${lines.length}`, lines };
    }

    const expected = [5, 7, 5];
    for (let i = 0; i < 3; i++) {
      if (lines[i].syllables !== expected[i]) {
        return { isHaiku: false, error: `Line ${i+1}: ${lines[i].syllables}/${expected[i]} syllables`, lines };
      }
    }

    return { isHaiku: true, error: null, lines };
  }
}

const haikuValidator = new HaikuValidator();


// ============================================================================
// COUNTKU UI — Live haiku display
// ============================================================================

function updateHaikuDisplay(input) {
    const display = document.getElementById('haikuDisplay');
    if (currentMode !== 'countku') { display.style.display = 'none'; return; }
    if (!input.trim()) { display.style.display = 'none'; return; }

    const result = haikuValidator.validate(input);
    display.style.display = 'block';

    for (let i = 0; i < 3; i++) {
        const el = document.getElementById('haikuLine' + (i + 1));
        if (result.lines && result.lines[i]) {
            const line = result.lines[i];
            const target = [5, 7, 5][i];
            const color = line.syllables === target ? '#4ade80' : '#ff8ab3';
            el.innerHTML = '<span style="color:' + color + '">' + line.words.join(' ') + ' (' + line.syllables + '/' + target + ')</span>';
        } else {
            el.textContent = '';
        }
    }

    const statusEl = document.getElementById('haikuStatus');
    // Trace mathResult in status
    countkuConverter.resetVariants();
    const _mr = countkuConverter.convertPhrase(input);
    const _mrText = _mr && typeof _mr === 'string' ? _mr.substring(0,30) : JSON.stringify(_mr);
    if (result.isHaiku) {
        statusEl.innerHTML = '<span style="color:#4ade80;">Valid 5-7-5! Math: ' + _mrText + '</span>';
    } else if (result.error) {
        statusEl.innerHTML = '<span style="color:#ff5050;">' + result.error + ' | Math: ' + _mrText + '</span>';
    } else if (result.lines.length > 0) {
        const total = result.lines.reduce((s, l) => s + l.syllables, 0);
        statusEl.textContent = 'Syllables: ' + total + '/17';
    } else {
        statusEl.textContent = 'Type to form a 5-7-5 haiku...';
    }

    // Debug console: show math conversion
    const debugConsole = document.getElementById('debugConsole');
    const debugMath = document.getElementById('debugMath');
    const debugEval = document.getElementById('debugEval');
    if (debugConsole && debugMath && debugEval) {
        debugConsole.style.display = 'block';
        countkuConverter.resetVariants();
        const mathResult = countkuConverter.convertPhrase(input);
        if (mathResult && typeof mathResult === 'string') {
            debugMath.textContent = '> ' + mathResult;
            try {
                // Direct eval — already converted, no mode swap needed
                const val = eval(mathResult);
                if (val !== null && !isNaN(val)) {
                    const target = currentNumber + 1;
                    const hit = Math.abs(val - target) < 0.0001 ? ' TARGET HIT!' : ' (target: ' + target + ')';
                    debugEval.textContent = '= ' + val + hit;
                } else {
                    debugEval.textContent = '= [eval error]';
                }
            } catch(e) {
                debugEval.textContent = '= [error: ' + e.message + ']';
            }
        } else if (mathResult && mathResult.error) {
            debugMath.textContent = '> [error: ' + mathResult.error + ']';
            debugEval.textContent = '';
        } else {
            debugMath.textContent = '> [no conversion]';
            debugEval.textContent = '';
        }
    }
}

// Direct execution (script is at end of body, DOM is ready)
(function() {
    const inputEl = document.getElementById('gameInput');
    if (inputEl) {
        inputEl.addEventListener('input', function(e) {
            if (currentMode === 'countku') updateHaikuDisplay(e.target.value);
        });
    }
})();



